using System;

interface IShape {
    double Area();
    string Name { get; }
}

class Circle : IShape {
    private double r;
    public Circle(double r) { this.r = r; }
    public double Area() => Math.PI * r * r;
    public string Name => "Circle";
}

class Square : IShape {
    private double s;
    public Square(double s) { this.s = s; }
    public double Area() => s * s;
    public string Name => "Square";
}

class Program {
    static void Main() {
        IShape[] shapes = { new Circle(3), new Square(4) };
        foreach (var sh in shapes)
            Console.WriteLine($"{sh.Name}: {sh.Area():F2}");
    }
}

using System;

interface IFlyable  { void Fly(); }
interface ISwimmable { void Swim(); }

class Duck : IFlyable, ISwimmable {
    public void Fly()  => Console.WriteLine("Duck flies");
    public void Swim() => Console.WriteLine("Duck swims");
}

class Program {
    static void Main() {
        var duck = new Duck();
        duck.Fly();
        duck.Swim();
        IFlyable f = duck;  // Duck IS an IFlyable
        f.Fly();
    }
}

using System;

interface IPrintable { string Format(); }

class Invoice : IPrintable {
    public string Format() => "Invoice #001: $100.00";
}
class Receipt : IPrintable {
    public string Format() => "Receipt: paid $100.00";
}

void PrintDocument(IPrintable doc) {
    Console.WriteLine($"Printing: {doc.Format()}");
}

class Program {
    static void Main() {
        PrintDocument(new Invoice());
        PrintDocument(new Receipt());
    }
}

using System;

interface ILogger {
    void Log(string msg);
    void LogError(string msg) => Log($"[ERROR] {msg}");
    void LogInfo(string msg) => Log($"[INFO] {msg}");
}

class ConsoleLogger : ILogger {
    public void Log(string msg) => Console.WriteLine(msg);
}

class Program {
    static void Main() {
        ILogger log = new ConsoleLogger();
        log.LogInfo("App started");
        log.LogError("Connection failed");
    }
}

using System;
using System.Collections.Generic;

class Student : IComparable<Student> {
    public string Name { get; set; }
    public int Grade { get; set; }

    public int CompareTo(Student other) => this.Grade.CompareTo(other.Grade);

    public override string ToString() => $"{Name}:{Grade}";
}

class Program {
    static void Main() {
        var students = new List<Student> {
            new Student { Name = "Carol", Grade = 92 },
            new Student { Name = "Alice", Grade = 85 },
            new Student { Name = "Bob",   Grade = 97 }
        };
        students.Sort();
        students.ForEach(s => Console.WriteLine(s));
    }
}

using System;
using System.Collections;
using System.Collections.Generic;

class NumberRange : IEnumerable<int> {
    private int start, end;
    public NumberRange(int start, int end) { this.start = start; this.end = end; }

    public IEnumerator<int> GetEnumerator() {
        for (int i = start; i <= end; i++) yield return i;
    }
    IEnumerator IEnumerable.GetEnumerator() => GetEnumerator();
}

class Program {
    static void Main() {
        foreach (int n in new NumberRange(1, 5)) {
            Console.Write($"{n} ");
        }
        Console.WriteLine();
    }
}

using System;

interface IReadable  { string Read(); }
interface IWritable  { void Write(string data); }
interface ISeekable  { void Seek(int pos); }

class FileStream : IReadable, IWritable, ISeekable {
    private string content = "";
    private int pos = 0;
    public string Read() => content.Substring(pos);
    public void Write(string data) { content += data; pos = content.Length; }
    public void Seek(int p) { pos = p; }
}

class Program {
    static void Main() {
        var fs = new FileStream();
        fs.Write("hello ");
        fs.Write("world");
        fs.Seek(0);
        Console.WriteLine(fs.Read());
    }
}

using System;

interface IMetric { double Measure(); }
interface IImperial { double Measure(); }

class Distance : IMetric, IImperial {
    private double metres;
    public Distance(double m) { metres = m; }
    double IMetric.Measure()   => metres;
    double IImperial.Measure() => metres * 3.28084;
}

class Program {
    static void Main() {
        var d = new Distance(10);
        Console.WriteLine(((IMetric)d).Measure());
        Console.WriteLine($"{((IImperial)d).Measure():F2}");
    }
}
